      "term": "TT System",
      "simpleDefinition": "An earthing arrangement that does not use a supplier's earth terminal, relying instead on a local earth electrode (rod) driven into the ground.",
      "anchor": "The earth rod system.",
      "misconception": "Assuming the supplier always provides an earth connection point."
    },
    {
      "term": "ADS",
      "simpleDefinition": "Automatic Disconnection of Supply; a safety strategy that cuts power instantly when a fault occurs to prevent electric shock.",
      "anchor": "Cut the power before it causes harm.",
      "misconception": "Viewing ADS as a single part rather than a combination of the CPC and the fuse/MCB."
    },
    {
      "term": "CPC",
      "simpleDefinition": "Circuit Protective Conductor; the specific wire (usually green and yellow) that provides a path for fault current to flow safely.",
      "anchor": "The fault current's dedicated path home.",
      "misconception": "Thinking the CPC carries electricity during normal, healthy operation."
    },
    {
      "term": "Zs",
      "simpleDefinition": "Total Earth Fault Loop Impedance; the total resistance of the entire path a fault current must travel to trigger a protective device.",
      "anchor": "The resistance of the full loop.",
      "misconception": "Confusing Zs with only the resistance of the green and yellow wire."
    },
    {
      "term": "PEN Conductor",
      "simpleDefinition": "Protective Earth and Neutral; a single conductor used in the supplier's network to provide both the neutral and earth functions.",
      "anchor": "Two jobs, one wire.",
      "misconception": "Thinking it is acceptable to use a PEN conductor within a standard domestic installation."
    }
  ],
  "anchorPhrases": [
    "Separate all the way back to the source",
    "Combined in the street, split at the door",
